84.     // Does not test unknown coupon codes returning zero discount.
85. 
86.     [TestMethod]
87.     public void ApplyCoupon_Save10_Applies10Percent()
88.     {
89.         var calc = new DiscountCalculator();
90.         var result = calc.ApplyCoupon(100m, "SAVE10");
91.         Assert.AreEqual(90m, result);
92.     }
93. 
